class EmployeeOnboardingService:
    def __init__(self, requesting_user):
        self.requesting_user = requesting_user
        self.correlation_id = str(uuid4())

    def onboard(self, payload):
        self._validate(payload)  # raises ValidationError if clinical role missing council fields
        with transaction.atomic():
            user = self._create_user(payload)  # password from mode + sets must_change_password=True for modes 1+2
            employee = Employee.objects.create(user=user, hire_date=..., employment_status=..., contract_type=...)
            self._audit('employee_created', 'employee', employee.id, new_data={...})
            self._audit('user_created', 'user', user.id, new_data={'mode': payload['auth_mode']})
            if payload['role'] in CLINICAL_ROLES:
                professional = Professional.objects.create(user=user, council_type=..., council_number=..., council_state=..., specialty=...)
                self._audit('professional_created', 'professional', professional.id)
            if payload['auth_mode'] == 'invite':
                # UserInvitation creation logic deferred to T6 — for now raise NotImplementedError if mode=invite (T6 will integrate)
                # OR: import the invitation creator from T6 once it exists. Plan: T3 ships with mode=invite as a 501 stub; T6 wires it.
                raise NotImplementedError('Invite mode requires T6 — wired by that task')
            if payload.get('setup_whatsapp') and self._whatsapp_enabled():
                user_id = user.id
                transaction.on_commit(lambda: setup_staff_whatsapp_channel.delay(user_id))
                self._audit('whatsapp_setup_queued', 'user', user.id)
        return employee

    def _audit(self, action, resource_type, resource_id, new_data=None):
        AuditLog.objects.create(user=self.requesting_user, action=action, resource_type=resource_type, resource_id=str(resource_id), new_data={**(new_data or {}), 'correlation_id': self.correlation_id})

    def _whatsapp_enabled(self):
        from apps.core.models import FeatureFlag
        tenant = connection.tenant  # django-tenants
        return FeatureFlag.objects.filter(tenant=tenant, module_key='whatsapp', is_enabled=True).exists()

