class PasswordChangeRequiredMiddleware:
    ALLOWLIST = {'/api/v1/auth/password', '/api/v1/auth/logout', '/api/v1/me'}

    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        if (
            getattr(request, 'user', None)
            and request.user.is_authenticated
            and getattr(request.user, 'must_change_password', False)
            and request.path not in self.ALLOWLIST
        ):
            from django.http import JsonResponse
            return JsonResponse(
                {'error': {'code': 'PASSWORD_CHANGE_REQUIRED', 'message': 'Senha temporária deve ser alterada antes de continuar.', 'redirect': '/auth/change-password'}},
                status=403,
            )
        return self.get_response(request)

