2. SetPasswordView (POST /auth/set-password/<token>/):
    permission_classes = []
    def post(self, request, token):
        try:
            payload = jwt.decode(token, settings.SECRET_KEY, algorithms=['HS256'])
        except (InvalidTokenError, ExpiredSignatureError):
            return Response({'error': 'INVALID_OR_EXPIRED_TOKEN'}, status=400)
        if payload.get('purpose') != 'password_set':
            return Response({'error': 'INVALID_TOKEN_PURPOSE'}, status=400)
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        invitation = UserInvitation.objects.filter(token_hash=token_hash).first()
        if not invitation:
            return Response({'error': 'INVITATION_NOT_FOUND'}, status=400)
        if invitation.is_consumed:
            return Response({'error': 'INVITATION_CONSUMED'}, status=400)
        if invitation.is_expired:
            return Response({'error': 'INVITATION_EXPIRED'}, status=410)
        password = request.data.get('password')
        # Validate password (min 8, complexity)
        invitation.user.set_password(password)
        invitation.user.must_change_password = False
        invitation.user.save()
        invitation.consumed_at = timezone.now()
        invitation.save()
        # Issue access JWT and return
        refresh = RefreshToken.for_user(invitation.user)
        return Response({'access': str(refresh.access_token), 'refresh': str(refresh)}, status=200)

