    @shared_task(bind=True, max_retries=3, default_retry_delay=60)
    def setup_staff_whatsapp_channel(self, user_id):
        try:
            from apps.core.models import User, AuditLog
            from apps.whatsapp.gateway import get_gateway
            user = User.objects.get(id=user_id)
            if not user.phone:
                logger.warning('setup_staff_whatsapp_channel: user %s has no phone, skipping', user_id)
                return
            gateway = get_gateway()
            gateway.setup_staff_channel(user.phone, user.full_name)  # or whatever the gateway method is
            AuditLog.objects.create(user=None, action='whatsapp_channel_created', resource_type='user', resource_id=str(user.id))
        except Exception as exc:
            try:
                self.retry(exc=exc)
            except MaxRetriesExceededError:
                logger.error('setup_staff_whatsapp_channel: persistent failure for user %s', user_id, exc_info=True)
                AuditLog.objects.create(user=None, action='whatsapp_setup_failed', resource_type='user', resource_id=str(user_id), new_data={'error': str(exc)})
                # Sentry will capture via the standard celery integration

